import{_ as i,o as e,c as a,ag as t}from"./chunks/framework.DGzMGr_a.js";const y=JSON.parse('{"title":"列表渲染中的 key 有什么作用？为什么不推荐用 index 作为 key？","description":"","frontmatter":{"title":"列表渲染中的 key 有什么作用？为什么不推荐用 index 作为 key？","difficulty":"easy","tags":["key","列表渲染","diff"],"estimate":10},"headers":[],"relativePath":"domains/react/qa/03-keys-in-lists.md","filePath":"domains/react/qa/03-keys-in-lists.md","lastUpdated":1783504823000}'),n={name:"domains/react/qa/03-keys-in-lists.md"};function r(l,s,k,d,h,o){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="问答题-03-初级-列表渲染中的-key-有什么作用-为什么不推荐用-index-作为-key" tabindex="-1">问答题 03（初级）：列表渲染中的 key 有什么作用？为什么不推荐用 index 作为 key？ <a class="header-anchor" href="#问答题-03-初级-列表渲染中的-key-有什么作用-为什么不推荐用-index-作为-key" aria-label="Permalink to &quot;问答题 03（初级）：列表渲染中的 key 有什么作用？为什么不推荐用 index 作为 key？&quot;">​</a></h1><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><code>key</code> 帮助 React 在 <strong>diff（协调）</strong> 过程中识别哪些元素被<strong>新增、删除或移动</strong>，从而复用 DOM 节点和组件实例，提升性能并保持状态正确。</p><p>React 通过 key 将新旧列表的元素做匹配：key 相同则复用并更新，key 不同则销毁重建。</p><p><strong>不推荐用数组 index 作为 key</strong> 的原因：当列表发生<strong>插入、删除、排序</strong>时，元素的 index 会变化，导致 key 与内容错位。React 会错误地复用节点，可能引发：</p><ul><li>表单输入等<strong>组件内部 state 错乱</strong>；</li><li>非受控组件显示旧数据；</li><li>不必要的重渲染或动画异常。</li></ul><p>只有当列表是<strong>静态、不重排、不增删</strong>时，用 index 才相对安全。应优先使用数据中稳定唯一的 id。</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{todos.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">todo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Todo</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{todo.id} {</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">todo} /&gt;)}  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ✅</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{todos.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">todo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Todo</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{i} {</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">todo} /&gt;)}   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ⚠️ 慎用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="追问" tabindex="-1">追问 <a class="header-anchor" href="#追问" aria-label="Permalink to &quot;追问&quot;">​</a></h2><h3 id="追问-1-key-需要全局唯一吗" tabindex="-1">追问 1：key 需要全局唯一吗？ <a class="header-anchor" href="#追问-1-key-需要全局唯一吗" aria-label="Permalink to &quot;追问 1：key 需要全局唯一吗？&quot;">​</a></h3><p><strong>参考答案</strong>：不需要全局唯一，只需在<strong>同一层级的兄弟节点之间唯一</strong>即可。不同列表可以有相同的 key。</p><h3 id="追问-2-key-会作为-props-传给组件吗" tabindex="-1">追问 2：key 会作为 props 传给组件吗？ <a class="header-anchor" href="#追问-2-key-会作为-props-传给组件吗" aria-label="Permalink to &quot;追问 2：key 会作为 props 传给组件吗？&quot;">​</a></h3><p><strong>参考答案</strong>：不会。<code>key</code> 是 React 保留属性，组件内部通过 <code>props.key</code> 取不到（为 undefined）。若需要该值，需额外用另一个 prop 传递，如 <code>id={todo.id}</code>。</p><h3 id="追问-3-给一个用-index-作-key-出问题的具体场景。" tabindex="-1">追问 3：给一个用 index 作 key 出问题的具体场景。 <a class="header-anchor" href="#追问-3-给一个用-index-作-key-出问题的具体场景。" aria-label="Permalink to &quot;追问 3：给一个用 index 作 key 出问题的具体场景。&quot;">​</a></h3><p><strong>参考答案</strong>：一个可勾选的 todo 列表，每项是带勾选状态的受控/非受控输入。若用 index 作 key，删除第一项后，原第二项接管了 index=0 的 key，React 复用了原第一项的 DOM/状态，导致勾选状态&quot;串位&quot;。改用 <code>todo.id</code> 即可修复。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/rendering-lists" target="_blank" rel="noreferrer">React: Rendering Lists</a>：key 在列表 diff 中的角色与选用原则</li><li><a href="https://react.dev/learn/render-and-commit" target="_blank" rel="noreferrer">React: Render and Commit</a>：协调阶段如何复用或重建节点</li><li><a href="https://react.dev/learn/preserving-and-resetting-state" target="_blank" rel="noreferrer">React: Preserving and Resetting State</a>：key 变化导致组件状态重置的行为</li></ul>`,18)])])}const g=i(n,[["render",r]]);export{y as __pageData,g as default};
